create table if not exists public.ambient_sessions (id uuid primary key default gen_random_uuid(), tenant_id text not null, session_key text not null, state text not null default 'active', created_at timestamptz not null default now());
create table if not exists public.contextual_memories (id uuid primary key default gen_random_uuid(), tenant_id text not null, session_id uuid not null references public.ambient_sessions(id), memory_blob text not null, created_at timestamptz not null default now());
create table if not exists public.interaction_continuity (id uuid primary key default gen_random_uuid(), session_id uuid not null references public.ambient_sessions(id), continuity_key text not null, created_at timestamptz not null default now());
create table if not exists public.ai_presence_states (id uuid primary key default gen_random_uuid(), session_id uuid not null references public.ambient_sessions(id), presence_state text not null, created_at timestamptz not null default now());
create table if not exists public.interaction_sessions (id uuid primary key default gen_random_uuid(), tenant_id text not null, interaction_key text not null, created_at timestamptz not null default now());
create table if not exists public.realtime_actions (id uuid primary key default gen_random_uuid(), interaction_session_id uuid not null references public.interaction_sessions(id), action_key text not null, created_at timestamptz not null default now());
create table if not exists public.commerce_action_routes (id uuid primary key default gen_random_uuid(), realtime_action_id uuid not null references public.realtime_actions(id), route_key text not null, created_at timestamptz not null default now());
create table if not exists public.interaction_workflows (id uuid primary key default gen_random_uuid(), interaction_session_id uuid not null references public.interaction_sessions(id), workflow_key text not null, created_at timestamptz not null default now());
create table if not exists public.multimodal_events (id uuid primary key default gen_random_uuid(), interaction_session_id uuid not null references public.interaction_sessions(id), event_type text not null, created_at timestamptz not null default now());
create table if not exists public.synchronized_interactions (id uuid primary key default gen_random_uuid(), event_id uuid not null references public.multimodal_events(id), sync_key text not null, created_at timestamptz not null default now());
create table if not exists public.modality_preferences (id uuid primary key default gen_random_uuid(), tenant_id text not null, modality_key text not null, weight numeric not null default 1, created_at timestamptz not null default now());
create table if not exists public.realtime_streams (id uuid primary key default gen_random_uuid(), interaction_session_id uuid not null references public.interaction_sessions(id), stream_key text not null, created_at timestamptz not null default now());
create table if not exists public.contextual_profiles (id uuid primary key default gen_random_uuid(), tenant_id text not null, profile_key text not null, created_at timestamptz not null default now());
create table if not exists public.workflow_contexts (id uuid primary key default gen_random_uuid(), profile_id uuid not null references public.contextual_profiles(id), workflow_key text not null, created_at timestamptz not null default now());
create table if not exists public.behavioral_awareness (id uuid primary key default gen_random_uuid(), profile_id uuid not null references public.contextual_profiles(id), signal_key text not null, created_at timestamptz not null default now());
create table if not exists public.continuity_recommendations (id uuid primary key default gen_random_uuid(), profile_id uuid not null references public.contextual_profiles(id), recommendation_key text not null, created_at timestamptz not null default now());
